def _shard_pattern(config_name: str, num_shards: int) -> str:
    if int(num_shards) <= 0:
        raise ValueError(f"Config {config_name} has no shards")
    if int(num_shards) == 1:
        suffix = "shard-000000.tar"
    else:
        suffix = f"shard-{{000000..{int(num_shards) - 1:06d}}}.tar"
    return f"{LLAVA_OV15_CONFIG_ROOT}/{config_name}/{suffix}"


def llava_ov15_group_roots():
    """Return stable per-task-family roots for LLaVA-OV1.5 image SFT.

    Each returned root is a list of exact brace-expanded tar shard patterns, not
    a broad `configs/*` glob. This avoids repeated bucket-wide listing and makes
    path mistakes fail on the exact config that is wrong.
    """
    roots = []
    weights = []
    names = []
    for group in LLAVA_OV15_GROUPS:
        # Use the per-config counts embedded below to construct exact ranges.
        config_to_shards = LLAVA_OV15_CONFIG_SHARDS
        group_roots = [
            _shard_pattern(cfg, config_to_shards[cfg])
            for cfg in group["configs"]
        ]
        roots.append(group_roots)
        weights.append(float(group["weight"]))
        names.append(group["name"])
    return names, roots, weights


def _config_base_weight(cfg, basis):
    """Per-config base weight under the chosen basis.

    'questions' = number of emitted (question, answer) training examples
    (images x avg QA-pairs-per-image); 'samples' = number of images; 'shards' =
    number of tar shards (image proxy). Falls back to shards when a count table
    is not populated, so the mixture is always well-defined.
    """
    shards = int(LLAVA_OV15_CONFIG_SHARDS[cfg])
    if basis == "questions":
        v = LLAVA_OV15_CONFIG_QUESTIONS.get(cfg)
    elif basis in ("samples", "images"):
        v = LLAVA_OV15_CONFIG_SAMPLES.get(cfg)
    elif basis == "shards":
        v = shards
    else:
        raise ValueError(f"Unknown llava_ov15 weight basis: {basis!r}")
    if v is None or float(v) <= 0:
        # fall back to shard proxy (or image count) if the table is missing.
        v = LLAVA_OV15_CONFIG_SAMPLES.get(cfg) or shards
    return float(v)


def llava_ov15_finegrained_roots(
    min_shards_standalone=32,
    basis="samples",
    group_weights=None,
    config_weights=None,
):
    """Return finer-grained per-config roots + relative weights for OV1.5 SFT.

    Each config with at least `min_shards_standalone` tar shards becomes its own
    StatefulRandomMix source; smaller configs in a group merge into one
    `<group>:_tail` source. The relative weight of each source is:

        sum over its configs of  base(config, basis) * config_mult(config)
        then multiplied by group_mult(group)

    where base is the per-config image/question/shard count (see basis), and the
    multipliers default to 1.0. Returned weights are RAW counts (x multipliers);
    the caller divides by 1e6 -> millions and applies the overall item multiplier.
    So `basis='samples'` weights each source by its image count in millions and
    `basis='questions'` by its emitted QA-pair count in millions (the natural
    uniform-image-read + expansion distribution), each sitting in the same
    millions-of-examples unit as the other datasets in the mixture; the multipliers
    let you re-weight any group or individual config.

    Giving each large config a fixed weight also makes its sampled share equal to
    its weight from step 1, independent of per-worker shard read order — which is
    what removes the valid-token window-mean drift of the coarse 13-group mixture.
    """
    group_weights = dict(group_weights or {})
    config_weights = dict(config_weights or {})
    names, roots, weights = [], [], []
    config_to_shards = LLAVA_OV15_CONFIG_SHARDS
    thr = max(1, int(min_shards_standalone))

    def base(cfg):
        return _config_base_weight(cfg, basis) * float(config_weights.get(cfg, 1.0))

    for group in LLAVA_OV15_GROUPS:
        gname = group["name"]
        gmult = float(group_weights.get(gname, 1.0))
        gconfigs = group["configs"]
        gshards = {c: int(config_to_shards[c]) for c in gconfigs}
        tail_configs = []
        for cfg in gconfigs:
            if gshards[cfg] >= thr:
                w = base(cfg) * gmult
                if w <= 0:
                    continue
                names.append(f"{gname}:{cfg}")
                roots.append([_shard_pattern(cfg, gshards[cfg])])
                weights.append(w)
            else:
                tail_configs.append(cfg)
        if tail_configs:
            tail_w = sum(base(c) for c in tail_configs) * gmult
            if tail_w > 0:
                names.append(f"{gname}:_tail")
                roots.append([_shard_pattern(c, gshards[c]) for c in tail_configs])
                weights.append(tail_w)
    return names, roots, weights


